// Generated by AI (UnitTest MCP)
import { execFileSync, spawnSync } from "node:child_process";
import { mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { afterEach, describe, expect, it } from "vitest";

const scopedCommit = join(
  dirname(fileURLToPath(import.meta.url)),
  "../../../scripts/scoped-commit.mjs"
);
const temporaryDirectories = [];

afterEach(() => {
  for (const directory of temporaryDirectories.splice(0)) {
    rmSync(directory, { recursive: true, force: true });
  }
});

const git = (cwd, args) =>
  execFileSync("git", args, { cwd, encoding: "utf8", stdio: "pipe" }).trim();

describe("scoped-commit", () => {
  it("commits only declared paths and preserves another agent's staged work", () => {
    const repo = mkdtempSync(join(tmpdir(), "mindleak-scoped-commit-"));
    temporaryDirectories.push(repo);
    git(repo, ["init", "-b", "main"]);
    git(repo, ["config", "user.name", "Scoped Commit Test"]);
    git(repo, ["config", "user.email", "scoped-commit@example.invalid"]);
    writeFileSync(join(repo, "base.txt"), "base\n");
    git(repo, ["add", "base.txt"]);
    git(repo, ["commit", "-m", "base"]);

    writeFileSync(join(repo, "mine.txt"), "declared\n");
    writeFileSync(join(repo, "foreign.txt"), "another agent\n");
    git(repo, ["add", "foreign.txt"]);

    const result = spawnSync(process.execPath, [scopedCommit, "-m", "scoped", "--", "mine.txt"], {
      cwd: repo,
      encoding: "utf8",
    });

    expect(result.status, `${result.stdout}\n${result.stderr}`).toBe(0);
    expect(git(repo, ["show", "--name-only", "--format=", "HEAD"])).toBe("mine.txt");
    expect(git(repo, ["diff", "--cached", "--name-only"])).toBe("foreign.txt");
    expect(result.stderr).toMatch(/staged paths are not yours/);
  }, 30_000);
});
